#!/usr/bin/env bash
# Build per-agent packages from the canonical sources at the repo root.
# Canonical (single source of truth): SKILL.md, SESSION-PREAMBLE.md, references/.
# Output: dist/codex/, dist/hermes/  (committed; DO NOT edit by hand — edit canonical + rebuild).
# Deterministic: clean + regenerate, no timestamps.
set -euo pipefail

ROOT="$(cd "$(dirname "$0")/.." && pwd)"
DIST="${ROOT}/dist"
SKILL="${ROOT}/SKILL.md"
PREAMBLE="${ROOT}/SESSION-PREAMBLE.md"
REFS="${ROOT}/references"

# Shared content placed identically for every agent. Agent-specific manifests /
# hooks are added by later build steps (plans 2 & 3).
rm -rf "${DIST}/codex" "${DIST}/hermes"
for agent in codex hermes; do
  mkdir -p "${DIST}/${agent}/skills/rookie-work/references"
  cp "${SKILL}" "${DIST}/${agent}/skills/rookie-work/SKILL.md"
  cp "${REFS}"/*.md "${DIST}/${agent}/skills/rookie-work/references/"
  cp "${PREAMBLE}" "${DIST}/${agent}/SESSION-PREAMBLE.md"
done

# --- Codex package: manifest (version injected from CC's manifest) + reuse CC hooks ---
VER="$(python3 -c "import json;print(json.load(open('${ROOT}/.claude-plugin/plugin.json'))['version'])")"
mkdir -p "${DIST}/codex/.codex-plugin" "${DIST}/codex/hooks"
sed "s/__VERSION__/${VER}/" "${ROOT}/build/templates/codex/plugin.json" > "${DIST}/codex/.codex-plugin/plugin.json"
cp "${ROOT}/hooks/hooks.json" "${ROOT}/hooks/session-start" "${ROOT}/hooks/run-hook.cmd" "${DIST}/codex/hooks/"

# --- Hermes package: pre_llm_call hook + co-located preamble + config snippet + INSTALL ---
mkdir -p "${DIST}/hermes/agent-hooks"
cp "${ROOT}/build/templates/hermes/rookie-work-inject.sh" "${DIST}/hermes/agent-hooks/rookie-work-inject.sh"
chmod +x "${DIST}/hermes/agent-hooks/rookie-work-inject.sh"
cp "${PREAMBLE}" "${DIST}/hermes/agent-hooks/SESSION-PREAMBLE.md"
cp "${ROOT}/build/templates/hermes/config-snippet.yaml" "${DIST}/hermes/config-snippet.yaml"
cp "${ROOT}/build/templates/hermes/INSTALL.md" "${DIST}/hermes/INSTALL.md"

# Generated-marker for the whole dist/ (SKILL.md frontmatter & JSON can't carry comments).
mkdir -p "${DIST}"
cat > "${DIST}/README.md" <<'EOF'
# GENERATED — DO NOT EDIT

Everything under `dist/` is generated by `build/build.sh` from the canonical
sources at the repo root (`SKILL.md`, `SESSION-PREAMBLE.md`, `references/`).
To change behavior, edit those canonical files and re-run `build/build.sh`.
EOF

echo "build: regenerated dist/codex and dist/hermes (shared content)"
